INSERT INTO public.dokkai_passages (level_id, order_index, title, text_content, content_json, vocab_notes, questions, is_premium) VALUES
(5, 6, '遺伝子工学の倫理 — Etika Rekayasa Genetika',
 '近年、遺伝子工学は目覚ましい発展を遂げています。科学者たちは、生物の遺伝子を自由に操作できるようになりつつあります。この技術は、私たちに大きな恩恵をもたらす可能性を秘めています。例えば、これまで治せなかった病気の治療法が見つかるかもしれません。農作物の品種改良によって、食糧問題の解決も期待されています。しかし、その一方で、深刻な倫理的問題も指摘されています。特に議論を呼んでいるのが、人間の遺伝子を操作することの是非です。親が子どもの容姿や能力を、生まれる前に選べるとしたらどうでしょうか。このような「デザイナーベビー」には、強い反対の声があります。命を人工的に操作することは、許されるのかという根本的な問いが残ります。また、遺伝子情報が、差別に利用される恐れも否定できません。技術が進歩するほど、それを使う人間の責任は重くなります。科学の進歩そのものを、止めることはできないでしょう。だからこそ、明確なルールと社会的な合意が不可欠です。私たちは、何ができるかだけでなく、何をすべきかを問わなければなりません。科学技術を、人類の幸福のために正しく使う知恵が求められています。倫理を伴わない技術は、時に危険な結果を招きます。未来の世代のためにも、慎重な議論を重ねていく必要があります。',
 '[
   {"jp":"近年、遺伝子工学は目覚ましい発展を遂げています。","furigana":"きんねん、いでんしこうがくはめざましいはってんをとげています。","romaji":"Kinnen, idenshi kougaku wa mezamashii hatten o togete imasu.","id":"Beberapa tahun terakhir, rekayasa genetika mengalami perkembangan yang luar biasa."},
   {"jp":"科学者たちは、生物の遺伝子を自由に操作できるようになりつつあります。","furigana":"かがくしゃたちは、せいぶつのいでんしをじゆうにそうさできるようになりつつあります。","romaji":"Kagakusha-tachi wa, seibutsu no idenshi o jiyuu ni sousa dekiru you ni naritsutsu arimasu.","id":"Para ilmuwan kian mampu memanipulasi gen makhluk hidup dengan bebas."},
   {"jp":"この技術は、私たちに大きな恩恵をもたらす可能性を秘めています。","furigana":"このぎじゅつは、わたしたちにおおきなおんけいをもたらすかのうせいをひめています。","romaji":"Kono gijutsu wa, watashitachi ni ooki na onkei o motarasu kanousei o himete imasu.","id":"Teknologi ini menyimpan kemungkinan membawa manfaat besar bagi kita."},
   {"jp":"例えば、これまで治せなかった病気の治療法が見つかるかもしれません。","furigana":"たとえば、これまでなおせなかったびょうきのちりょうほうがみつかるかもしれません。","romaji":"Tatoeba, kore made naosenakatta byouki no chiryouhou ga mitsukaru kamoshiremasen.","id":"Misalnya, mungkin ditemukan pengobatan bagi penyakit yang selama ini tak tersembuhkan."},
   {"jp":"農作物の品種改良によって、食糧問題の解決も期待されています。","furigana":"のうさくぶつのひんしゅかいりょうによって、しょくりょうもんだいのかいけつもきたいされています。","romaji":"Nousakubutsu no hinshu kairyou ni yotte, shokuryou mondai no kaiketsu mo kitai sarete imasu.","id":"Lewat pemuliaan varietas tanaman, penyelesaian masalah pangan pun diharapkan."},
   {"jp":"しかし、その一方で、深刻な倫理的問題も指摘されています。","furigana":"しかし、そのいっぽうで、しんこくなりんりてきもんだいもしてきされています。","romaji":"Shikashi, sono ippou de, shinkoku na rinriteki mondai mo shiteki sarete imasu.","id":"Namun di sisi lain, masalah etis yang serius pun ditunjukkan."},
   {"jp":"特に議論を呼んでいるのが、人間の遺伝子を操作することの是非です。","furigana":"とくにぎろんをよんでいるのが、にんげんのいでんしをそうさすることのぜひです。","romaji":"Toku ni giron o yonde iru no ga, ningen no idenshi o sousa suru koto no zehi desu.","id":"Yang terutama memicu perdebatan adalah boleh-tidaknya memanipulasi gen manusia."},
   {"jp":"親が子どもの容姿や能力を、生まれる前に選べるとしたらどうでしょうか。","furigana":"おやがこどものようしやのうりょくを、うまれるまえにえらべるとしたらどうでしょうか。","romaji":"Oya ga kodomo no youshi ya nouryoku o, umareru mae ni eraberu to shitara dou deshou ka.","id":"Bagaimana jika orang tua bisa memilih penampilan dan kemampuan anaknya sebelum lahir?"},
   {"jp":"このような「デザイナーベビー」には、強い反対の声があります。","furigana":"このような「デザイナーベビー」には、つよいはんたいのこえがあります。","romaji":"Kono you na \"dezainaa bebii\" ni wa, tsuyoi hantai no koe ga arimasu.","id":"Terhadap \"designer baby\" semacam ini, ada suara penolakan yang kuat."},
   {"jp":"命を人工的に操作することは、許されるのかという根本的な問いが残ります。","furigana":"いのちをじんこうてきにそうさすることは、ゆるされるのかというこんぽんてきなといがのこります。","romaji":"Inochi o jinkouteki ni sousa suru koto wa, yurusareru no ka to iu konponteki na toi ga nokorimasu.","id":"Tersisa pertanyaan mendasar: bolehkah memanipulasi kehidupan secara buatan?"},
   {"jp":"また、遺伝子情報が、差別に利用される恐れも否定できません。","furigana":"また、いでんしじょうほうが、さべつにりようされるおそれもひていできません。","romaji":"Mata, idenshi jouhou ga, sabetsu ni riyou sareru osore mo hitei dekimasen.","id":"Selain itu, tak bisa disangkal risiko data genetik dipakai untuk diskriminasi."},
   {"jp":"技術が進歩するほど、それを使う人間の責任は重くなります。","furigana":"ぎじゅつがしんぽするほど、それをつかうにんげんのせきにんはおもくなります。","romaji":"Gijutsu ga shinpo suru hodo, sore o tsukau ningen no sekinin wa omoku narimasu.","id":"Makin maju teknologinya, makin berat tanggung jawab manusia yang memakainya."},
   {"jp":"科学の進歩そのものを、止めることはできないでしょう。","furigana":"かがくのしんぽそのものを、とめることはできないでしょう。","romaji":"Kagaku no shinpo sono mono o, tomeru koto wa dekinai deshou.","id":"Kemajuan sains itu sendiri agaknya tak mungkin dihentikan."},
   {"jp":"だからこそ、明確なルールと社会的な合意が不可欠です。","furigana":"だからこそ、めいかくなルールとしゃかいてきなごういがふかけつです。","romaji":"Dakara koso, meikaku na ruuru to shakaiteki na goui ga fukaketsu desu.","id":"Justru karena itu, aturan yang jelas dan kesepakatan sosial mutlak diperlukan."},
   {"jp":"私たちは、何ができるかだけでなく、何をすべきかを問わなければなりません。","furigana":"わたしたちは、なにができるかだけでなく、なにをすべきかをとわなければなりません。","romaji":"Watashitachi wa, nani ga dekiru ka dake de naku, nani o subeki ka o towanakereba narimasen.","id":"Kita harus mempertanyakan bukan hanya apa yang bisa, tapi apa yang seharusnya dilakukan."},
   {"jp":"科学技術を、人類の幸福のために正しく使う知恵が求められています。","furigana":"かがくぎじゅつを、じんるいのこうふくのためにただしくつかうちえがもとめられています。","romaji":"Kagaku gijutsu o, jinrui no koufuku no tame ni tadashiku tsukau chie ga motomerarete imasu.","id":"Dibutuhkan kebijaksanaan memakai iptek dengan benar demi kebahagiaan umat manusia."},
   {"jp":"倫理を伴わない技術は、時に危険な結果を招きます。","furigana":"りんりをともなわないぎじゅつは、ときにきけんなけっかをまねきます。","romaji":"Rinri o tomonawanai gijutsu wa, toki ni kiken na kekka o manekimasu.","id":"Teknologi tanpa disertai etika kadang mengundang akibat yang berbahaya."},
   {"jp":"未来の世代のためにも、慎重な議論を重ねていく必要があります。","furigana":"みらいのせだいのためにも、しんちょうなぎろんをかさねていくひつようがあります。","romaji":"Mirai no sedai no tame ni mo, shinchou na giron o kasanete iku hitsuyou ga arimasu.","id":"Demi generasi mendatang pun, kita perlu terus menumpuk diskusi yang cermat."}
